import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 25;

const Inventory = ({ clientCode }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);

  useEffect(() => {
    if (!clientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: clientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [clientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #f8fafc 0%, #e0e7ff 100%)' }}>
      <Header userInfo={{ ClientCode: clientCode }} />
      <div className="container py-4">
        <div className="d-flex flex-wrap align-items-center justify-content-between mb-4 gap-2">
          <h2 className="mb-0" style={{ fontWeight: 700, color: '#333', letterSpacing: 1 }}>
            <i className="fas fa-box me-2" style={{ color: '#5470FF' }}></i>
            Inventory Label List
          </h2>
          <div className="d-flex align-items-center gap-2" style={{ minWidth: 350 }}>
            <div style={{ position: 'relative', width: '100%' }}>
              <input
                ref={searchInputRef}
                type="text"
                className="form-control ps-5"
                style={{ borderRadius: 10, boxShadow: '0 2px 8px #5470ff22', height: 40 }}
                placeholder="Search by Item Code, Product Name, Branch..."
                value={search}
                onChange={handleSearchChange}
              />
              <span style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: '#5470FF', fontSize: 18 }}>
                <i className="fas fa-search"></i>
              </span>
            </div>
            <button
              className="btn btn-success d-flex align-items-center"
              style={{ borderRadius: 10, fontWeight: 500, boxShadow: '0 2px 8px #22bb3355', height: 40 }}
              onClick={handleExport}
            >
              <i className="fas fa-file-excel me-2"></i> Export
            </button>
          </div>
        </div>
        <div className="card border-0 shadow" style={{ borderRadius: 14, background: '#fff', boxShadow: '0 4px 24px #0001', padding: '0.5rem 0.5rem 1.5rem 0.5rem' }}>
          <div className="card-body p-0">
            {loading && <div className="alert alert-info m-4">Loading...</div>}
            {error && <div className="alert alert-danger m-4">{error}</div>}
            {!loading && !error && filteredLabels.length === 0 && (
              <div className="alert alert-warning m-4">No labeled stock found.</div>
            )}
            {!loading && !error && filteredLabels.length > 0 && (
              <div className="table-responsive" style={{ borderRadius: 10, overflow: 'hidden', boxShadow: '0 1px 8px #0001' }}>
                <table className="table table-bordered table-hover align-middle mb-0" style={{ minWidth: 900, width: '100%', background: '#fff', borderRadius: 10, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0 }}>
                  <thead style={{ position: 'sticky', top: 0, zIndex: 2, background: '#fff', borderTopLeftRadius: 10, borderTopRightRadius: 10, boxShadow: '0 2px 8px #0001' }}>
                    <tr style={{ borderRadius: 10 }}>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopLeftRadius: 10 }}>Item Code
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.ItemCode || ''} onChange={e => handleFilterChange('ItemCode', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('ItemCode').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Product Name
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.ProductName || ''} onChange={e => handleFilterChange('ProductName', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('ProductName').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Category
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.CategoryName || ''} onChange={e => handleFilterChange('CategoryName', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('CategoryName').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Purity
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.PurityName || ''} onChange={e => handleFilterChange('PurityName', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('PurityName').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Gross Wt
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.GrossWt || ''} onChange={e => handleFilterChange('GrossWt', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('GrossWt').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Net Wt
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.NetWt || ''} onChange={e => handleFilterChange('NetWt', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('NetWt').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff' }}>Branch
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.BranchName || ''} onChange={e => handleFilterChange('BranchName', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('BranchName').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                      <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopRightRadius: 10 }}>Status
                        <select className="form-select form-select-sm mt-1" style={{ minWidth: 80 }} value={filters.Status || ''} onChange={e => handleFilterChange('Status', e.target.value)}>
                          <option value="">All</option>
                          {getUnique('Status').map(val => <option key={val} value={val}>{val}</option>)}
                        </select>
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {paginatedLabels.map((label, idx) => (
                      <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer' }}
                        onMouseOver={e => e.currentTarget.style.background = '#f0f0f0'}
                        onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                      >
                        <td style={{ fontWeight: 600, color: '#222', letterSpacing: 1 }}>{label.ItemCode}</td>
                        <td>{label.ProductName}</td>
                        <td>{label.CategoryName}</td>
                        <td>{label.PurityName}</td>
                        <td>{label.GrossWt}</td>
                        <td>{label.NetWt}</td>
                        <td>{label.BranchName}</td>
                        <td>
                          <span className={`badge bg-${label.Status === 'Active' ? 'success' : 'secondary'}`} style={{ fontSize: '1em', padding: '6px 14px', borderRadius: 12, fontWeight: 600 }}>{label.Status}</span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
          {/* Pagination */}
          {totalPages > 1 && !search && (
            <div className="d-flex justify-content-between align-items-center p-3 border-top" style={{ background: '#f8fafc', borderRadius: '0 0 16px 16px' }}>
              <span style={{ color: '#666', fontSize: '0.95rem' }}>
                Showing {((page - 1) * PAGE_SIZE) + 1} - {Math.min(page * PAGE_SIZE, filteredLabels.length)} of {filteredLabels.length}
              </span>
              <nav>
                <ul className="pagination mb-0">
                  <li className={`page-item${page === 1 ? ' disabled' : ''}`}><button className="page-link" onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                  {[...Array(totalPages)].map((_, idx) => (
                    <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}>
                      <button className="page-link" onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button>
                    </li>
                  ))}
                  <li className={`page-item${page === totalPages ? ' disabled' : ''}`}><button className="page-link" onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
                </ul>
              </nav>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Inventory;
